using BotFramework.Discord.Commands;using BotFramework.Discord.Routing;using Games.DiceCube.Application.Services;
namespace Games.DiceCube.Discord;
public sealed class DiceCubeDiscordHandler(IDiceCubeService service):IDiscordMessageHandler{public bool CanHandle(DiscordMessageContext c)=>DiscordCommand.Is(c,"dice");public async Task HandleAsync(DiscordMessageContext c){var p=DiscordCommand.Parts(c);if(p.Length!=2||!int.TryParse(p[1],out var amount)||amount<=0){await DiscordCommand.ReplyAsync(c,"Использование: `dice <ставка>`");return;}var u=DiscordCommand.UserId(c);var s=DiscordCommand.ScopeId(c);var src=DiscordCommand.SourceId(c);var n=DiscordCommand.DisplayName(c);_ = await service.PlaceBetAsync(u,n,s,amount,src,c.CancellationToken);var face=DiscordCommand.RandomFace(1,6);var r=await service.RollAsync(u,n,s,face,c.CancellationToken);await DiscordCommand.ReplyResultAsync(c,r,"Dice: "+face);}}
public static class DiceCubeDiscordModule{public static IServiceCollection AddDiceCubeDiscord(this IServiceCollection s)=>s.AddScoped<IDiscordMessageHandler,DiceCubeDiscordHandler>();}
